import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final BufferedInputStream in = new BufferedInputStream(System.in);
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private int read() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        Long nextLong() throws IOException {
            int c;
            do {
                c = read();
                if (c == -1) return null;
            } while (c <= ' ');
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = read();
            }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = read();
            }
            return neg ? -val : val;
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        Long tLong = fs.nextLong();
        if (tLong == null) return;
        int T = tLong.intValue();
        StringBuilder sb = new StringBuilder();
        outer:
        for (int tc = 0; tc < T; tc++) {
            Long nL = fs.nextLong();
            Long mL = fs.nextLong();
            Long hL = fs.nextLong();
            if (nL == null || mL == null || hL == null) break;
            int N = nL.intValue();
            int M = mL.intValue();
            long H = hL;
            long[] cars = new long[N];
            for (int i = 0; i < N; i++) {
                Long val = fs.nextLong();
                if (val == null) break outer; // malformed input, stop processing further test cases
                cars[i] = val;
            }
            long[] outlets = new long[M];
            for (int i = 0; i < M; i++) {
                Long val = fs.nextLong();
                if (val == null) break outer; // malformed input
                outlets[i] = val;
            }
            Arrays.sort(cars);
            Arrays.sort(outlets);
            int i = N - 1, j = M - 1;
            long ans = 0;
            while (i >= 0 && j >= 0) {
                long gen = outlets[j] * H;
                ans += gen <= cars[i] ? gen : cars[i];
                i--;
                j--;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

